<span class="line">    <span class="token keyword">switch</span> <span class="token punctuation">(</span>mapData<span class="token punctuation">[</span><span class="token string-literal"><span class="token string">'type'</span></span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
