<span class="line">          <span class="token class-name">List</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token keyword">dynamic</span><span class="token punctuation">></span></span> peers <span class="token operator">=</span> data<span class="token punctuation">;</span></span>
<span class="line">          <span class="token keyword">if</span> <span class="token punctuation">(</span>onPeersUpdate <span class="token operator">!=</span> <span class="token keyword">null</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token class-name">Map</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">,</span> <span class="token keyword">dynamic</span><span class="token punctuation">></span></span> event <span class="token operator">=</span> <span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">,</span> <span class="token keyword">dynamic</span><span class="token punctuation">></span></span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line">            event<span class="token punctuation">[</span><span class="token string-literal"><span class="token string">'self'</span></span><span class="token punctuation">]</span> <span class="token operator">=</span> _selfId<span class="token punctuation">;</span></span>
<span class="line">            event<span class="token punctuation">[</span><span class="token string-literal"><span class="token string">'peers'</span></span><span class="token punctuation">]</span> <span class="token operator">=</span> peers<span class="token punctuation">;</span></span>
<span class="line">            onPeersUpdate<span class="token operator">?</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>event<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">          <span class="token punctuation">}</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">        <span class="token keyword">break</span><span class="token punctuation">;</span></span>
<span class="line">      <span class="token keyword">case</span> <span class="token string-literal"><span class="token string">'offer'</span></span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token punctuation">{</span></span>
<span class="line">          <span class="token keyword">var</span> peerId <span class="token operator">=</span> data<span class="token punctuation">[</span><span class="token string-literal"><span class="token string">'from'</span></span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">          <span class="token keyword">var</span> description <span class="token operator">=</span> data<span class="token punctuation">[</span><span class="token string-literal"><span class="token string">'description'</span></span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">          <span class="token keyword">var</span> media <span class="token operator">=</span> data<span class="token punctuation">[</span><span class="token string-literal"><span class="token string">'media'</span></span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
