<span class="line">          <span class="token keyword">var</span> newSession <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">_createSession</span><span class="token punctuation">(</span>session<span class="token punctuation">,</span></span>
<span class="line">              peerId<span class="token punctuation">:</span> peerId<span class="token punctuation">,</span></span>
<span class="line">              sessionId<span class="token punctuation">:</span> sessionId<span class="token punctuation">,</span></span>
<span class="line">              media<span class="token punctuation">:</span> media<span class="token punctuation">,</span></span>
<span class="line">              screenSharing<span class="token punctuation">:</span> <span class="token boolean">false</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
