<span class="line">              <span class="token class-name">RTCSessionDescription</span><span class="token punctuation">(</span>description<span class="token punctuation">[</span><span class="token string-literal"><span class="token string">'sdp'</span></span><span class="token punctuation">]</span><span class="token punctuation">,</span> description<span class="token punctuation">[</span><span class="token string-literal"><span class="token string">'type'</span></span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">          <span class="token keyword">if</span> <span class="token punctuation">(</span>newSession<span class="token punctuation">.</span>remoteCandidates<span class="token punctuation">.</span>isNotEmpty<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">            newSession<span class="token punctuation">.</span>remoteCandidates<span class="token punctuation">.</span><span class="token function">forEach</span><span class="token punctuation">(</span><span class="token punctuation">(</span>candidate<span class="token punctuation">)</span> <span class="token keyword">async</span> <span class="token punctuation">{</span></span>
<span class="line">              <span class="token keyword">await</span> newSession<span class="token punctuation">.</span>pc<span class="token operator">?</span><span class="token punctuation">.</span><span class="token function">addCandidate</span><span class="token punctuation">(</span>candidate<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            newSession<span class="token punctuation">.</span>remoteCandidates<span class="token punctuation">.</span><span class="token function">clear</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">          <span class="token punctuation">}</span></span>
<span class="line">          onCallStateChange<span class="token operator">?</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>newSession<span class="token punctuation">,</span> <span class="token class-name">CallState</span><span class="token punctuation">.</span>callStateNew<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">          onCallStateChange<span class="token operator">?</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>newSession<span class="token punctuation">,</span> <span class="token class-name">CallState</span><span class="token punctuation">.</span>callStateRinging<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
