<span class="line">          <span class="token keyword">var</span> sessionId <span class="token operator">=</span> data<span class="token punctuation">[</span><span class="token string-literal"><span class="token string">'session_id'</span></span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
